import{_ as a,c as o,m as e,a as s,t as i,a5 as l,o as c}from"./chunks/framework.DwbewbAn.js";const r="/assets/server.B3uebfUR.png",n="/assets/client.Df4C4QxM.png",p="/assets/socket.CP_DMjrd.png",g=JSON.parse('{"title":"C++ socket 介绍","description":"","frontmatter":{"title":"C++ socket 介绍"},"headers":[],"relativePath":"doc/编程语言/后端/Cplus/网络编程/socket/socket.md","filePath":"packages/doc/src/编程语言/后端/Cplus/网络编程/socket/socket.md","lastUpdated":1711551906000}'),h={name:"doc/编程语言/后端/Cplus/网络编程/socket/socket.md"},d={id:"frontmatter-title",tabindex:"-1"},k=e("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":'Permalink to "{{ $frontmatter.title }}"'},"​",-1),_=l('<p>应用程序通过socket向网络发出请求或者回应</p><h2 id="种类" tabindex="-1">种类 <a class="header-anchor" href="#种类" aria-label="Permalink to &quot;种类&quot;">​</a></h2><ul><li><p>流式套接字（SOCK_STREAM） TCP</p></li><li><p>数据报套接字(SOCK_DGRAM) UDP</p></li><li><p>原始套接字(SOCK_RAW) 不常用</p></li></ul><h2 id="服务端" tabindex="-1">服务端 <a class="header-anchor" href="#服务端" aria-label="Permalink to &quot;服务端&quot;">​</a></h2><p>建立socket，声明自身的port和IP，并绑定到socket，使用listen监听，然后不断用accept去查看是否有连接。</p><p>如果有，捕获socket，并通过recv获取消息的内容，通信完成后调用closeSocket关闭这个对应accept到的socket。</p><p>如果不需要等待任何客户端连接，那么用closeSocket直接关闭自身的socket。</p><p><img src="'+r+'" alt="img"></p><h2 id="客户端" tabindex="-1">客户端 <a class="header-anchor" href="#客户端" aria-label="Permalink to &quot;客户端&quot;">​</a></h2><p>建立socket，通过端口号和地址确定目标服务器，使用Connect连接到服务器，send发送消息，等待处理，通信完成后调用closeSocket关闭socket</p><p><img src="'+n+'" alt="img"></p><h2 id="socket-服务端和客户端通信流程" tabindex="-1">socket 服务端和客户端通信流程 <a class="header-anchor" href="#socket-服务端和客户端通信流程" aria-label="Permalink to &quot;socket 服务端和客户端通信流程&quot;">​</a></h2><p><img src="'+p+'" alt="img"></p><h1 id="服务端-1" tabindex="-1">服务端 <a class="header-anchor" href="#服务端-1" aria-label="Permalink to &quot;服务端&quot;">​</a></h1><ul><li>socket()</li><li>bind()</li><li>listen()</li><li>accept()</li><li>closesocket()</li></ul><h1 id="客户端-1" tabindex="-1">客户端 <a class="header-anchor" href="#客户端-1" aria-label="Permalink to &quot;客户端&quot;">​</a></h1><ul><li>socket()</li><li>bind()</li><li>connect()</li><li>htons()</li><li>recv()</li><li>send()</li><li>closesocket()</li></ul><h2 id="htons" tabindex="-1">htons() <a class="header-anchor" href="#htons" aria-label="Permalink to &quot;htons()&quot;">​</a></h2><p>htons是将整型变量从主机字节顺序转变成网络字节顺序， 就是整数在地址空间存储方式变为高位字节存放在内存的低地址处。</p><p>网络字节顺序是TCP/IP中规定好的一种数据表示格式，它与具体的CPU类型、操作系统等无关，从而可以保证数据在不同主机之间传输时能够被正确解释，网络字节顺序采用big-endian排序方式。</p>',20);function m(t,u,f,b,P,C){return c(),o("div",null,[e("h1",d,[s(i(t.$frontmatter.title)+" ",1),k]),_])}const S=a(h,[["render",m]]);export{g as __pageData,S as default};
